namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect(":memory:");

  // Create tables
  auto create_user_table = sqlgen::create_table<User>;
  auto create_friendship_table = sqlgen::create_table<Friendship>;

  create_user_table(conn);
  create_friendship_table(conn);

  // Insert data
  sqlgen::insert(users).execute(conn);
  sqlgen::insert(friendships).execute(conn);

  // Query 1: Mutual friends using SELF-JOIN and HAVING
  auto mutual_friends_query = sqlgen::select_from<User, "u1">(
      "username"_t1.as<"user1_name">(),
      "username"_t4.as<"user2_name">(),
      sqlgen::count().as<"mutual_friends">()
  )
  | sqlgen::inner_join<Friendship, "f1">("user_id"_t1 == "user_id1"_t2)
  | sqlgen::inner_join<Friendship, "f2">("user_id2"_t2 == "user_id1"_t3)
  | sqlgen::inner_join<User, "u2">("user_id2"_t3 == "user_id"_t4)
  | sqlgen::where("user_id"_t1 < "user_id"_t4 && 
      sqlgen::exists(
          sqlgen::select_from<Friendship, "f3">(
              "user_id1"_t1 == "user_id"_t1 && "user_id2"_t1 == "user_id"_t4
          )
      )
  )
  | sqlgen::group_by("user_id"_t1, "user_id"_t4)
  | sqlgen::having(sqlgen::count() > 0)
  | sqlgen::to<std::vector<FriendConnection>>;

  // Query 2: Users with more than average friends using nested query
  auto avg_friends_query = sqlgen::select_from<User, "u">(
      "user_id"_t1,
      "username"_t1,
      sqlgen::count().as<"friend_count">()
  )
  | sqlgen::left_join(Friendship, "f")("user_id"_t1 == "user_id1"_t2)
  | sqlgen::group_by("user_id"_t1, "username"_t1)
  | sqlgen::having("friend_count"_t1 > 
      sqlgen::select_from<Friendship, "f_avg">(
          sqlgen::avg(sqlgen::count().as<"friend_count">())
      )
  )
  | sqlgen::order_by("friend_count"_t1.desc());

  // Execute queries and return results
  auto mutual_friends_result = mutual_friends_query(conn);
  auto avg_friends_result = avg_friends_query(conn);

  return mutual_friends_result;
}

}  // namespace analyze_social_network

