    "order_id"_c,
    "product_id"_c,
    "unit_price"_c,
    "quantity"_c,
    "discount_rate"_c,
    "tax_rate"_c,

    // Arithmetic operations and calculations
    ("unit_price"_c * "quantity"_c) | sqlgen::as<"gross_total">,
    ("unit_price"_c * "quantity"_c * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100.0)) | sqlgen::as<"discounted_total">,
    (("unit_price"_c * "quantity"_c * (1 - sqlgen::coalesce("discount_rate"_c, 0.0)/100.0)) * (1 + sqlgen::coalesce("tax_rate"_c, 0.0)/100.0)) | sqlgen::as<"final_total">,
