    ("unit_price"_c * "quantity"_c / "quantity"_c) | sqlgen::as<"unit_cost">,
    ("quantity"_c % 10) | sqlgen::as<"quantity_group">,
    ("unit_price"_c * 0.3) | sqlgen::as<"estimated_profit">
