#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool - true if cascade deletion worked, false otherwise.
 */
bool cascade_delete_demo() {
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // 2. Create tables by writing sample data (tables will be created automatically)
  std::vector<Parent> parents = {{1, "Parent 1"}, {2, "Parent 2"}};
  std::vector<Child> children = {{1, 1, "Child of Parent 1"}, {2, 2, "Child of Parent 2"}};

  sqlgen::write(conn, parents);
  sqlgen::write(conn, children);

  // 3. Delete parent with ID 1 and verify cascade deletion
  auto delete_result = (sqlgen::delete_from<Parent> | sqlgen::where("parent_id"_c == 1))(conn);

  if (!delete_result) {
    return false; // Deletion failed
  }

  // 4. Verify if child rows are deleted automatically
  auto remaining_children = sqlgen::read<std::vector<Child>>(conn);

  // Check if all children referencing deleted parent are removed
  bool cascade_worked = true;
  for (const auto& child : remaining_children) {
    if (child.parent_id == 1) {
      cascade_worked = false;
      break;
    }
  }

  return cascade_worked;
}

}  // namespace cascade_delete_demo
